#include <bits/stdc++.h>
using namespace std;
typedef long long ll;
int main(){
    ll n;
    bool flag=true;
    cin>>n;
    for(ll i=2;i*i<=n;i++){
    	if(n%i!=0)continue; 
        ll sum=0;
        while(n%i==0 && n>1){
            n/=i;
            sum++;
        }
        if(!flag)
            cout<<" * ";
        else flag=false;
        cout<<i;
        if(sum>1)cout<<"^"<<sum;
    }
    if(n>1){
    	if(!flag)cout<<" * "<<n;
    	else cout<<n;
	}
    return 0;
}
